class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        n = int(s, 2)
        MOD = 10**9 + 7
        dp = [[0]*(k+1) for _ in range(n+1)]
        dp[0][0] = 1
        for i in range(1, n+1):
            cnt = bin(i).count('1')
            for j in range(k, -1, -1):
                dp[i][j] = dp[i-1][j]
                if j >= cnt:
                    dp[i][j] += dp[i-1][j-cnt]
                dp[i][j] %= MOD
        return sum(dp[i][k] for i in range(n))

